// Tokyo Night Aurora — floating islands
{
  "layer": "top",
  "position": "top",
  "height": 34,
  "spacing": 0,
  "margin-top": 8,
  "margin-left": 14,
  "margin-right": 14,
  "modules-left": ["custom/launcher", "hyprland/workspaces", "hyprland/window"],
  "modules-center": ["clock"],
  "modules-right": ["tray", "pulseaudio", "network", "cpu", "memory", "battery", "custom/power"],

  "custom/launcher": { "format": "󰣇", "on-click": "wofi --show drun", "tooltip": false },
  "hyprland/workspaces": {
    "format": "{icon}",
    "on-click": "activate",
    "format-icons": { "active": "", "default": "", "empty": "" },
    "persistent-workspaces": { "*": 5 }
  },
  "hyprland/window": { "format": "  {title}", "max-length": 45, "separate-outputs": true },
  "clock": {
    "format": "  {:%H:%M}   {:%a %d %b}",
    "tooltip-format": "<tt><big>{calendar}</big></tt>"
  },
  "cpu": { "format": "  {usage}%", "interval": 2 },
  "memory": { "format": "  {percentage}%" },
  "network": {
    "format-wifi": "  {essid}",
    "format-ethernet": "  wired",
    "format-disconnected": "󰤭  off",
    "tooltip-format": "{ifname}  {ipaddr}"
  },
  "pulseaudio": {
    "format": "{icon}  {volume}%",
    "format-muted": "  muted",
    "format-icons": { "default": ["", "", ""] },
    "on-click": "pavucontrol"
  },
  "battery": {
    "format": "{icon}  {capacity}%",
    "format-charging": "  {capacity}%",
    "format-icons": ["", "", "", "", ""],
    "states": { "warning": 30, "critical": 15 }
  },
  "tray": { "spacing": 10 },
  "custom/power": { "format": "󰐥", "on-click": "hyprlock", "tooltip": false }
}

/* Tokyo Night Aurora */
* {
  font-family: "JetBrainsMono Nerd Font", monospace;
  font-size: 13px;
  font-weight: bold;
  min-height: 0;
}
window#waybar { background: transparent; }

#custom-launcher, #workspaces, #window, #clock, #tray,
#pulseaudio, #network, #cpu, #memory, #battery, #custom-power {
  background: alpha(#1a1b26, 0.82);
  border: 1px solid alpha(#7aa2f7, 0.18);
  border-radius: 14px;
  padding: 1px 12px;
  margin: 3px 3px;
  box-shadow: 0 2px 6px alpha(#11121a, 0.45);
}

#custom-launcher {
  color: #7aa2f7;
  font-size: 18px;
  padding: 0 14px;
  margin-left: 4px;
}
#custom-launcher:hover { color: #bb9af7; }

#workspaces { padding: 1px 6px; }
#workspaces button {
  color: #565f89;
  padding: 0 6px;
  margin: 0 1px;
  border-radius: 10px;
  transition: all 0.25s cubic-bezier(0.55, 0, 0.28, 1.68);
}
#workspaces button.active {
  color: #1a1b26;
  background: linear-gradient(45deg, #7aa2f7, #bb9af7);
  box-shadow: 0 0 10px alpha(#7aa2f7, 0.55);
  padding: 0 12px;
}
#workspaces button:hover {
  color: #c0caf5;
  background: alpha(#7aa2f7, 0.20);
  box-shadow: none;
}

#window { color: #a9b1d6; }
#clock { color: #7dcfff; }
#cpu { color: #9ece6a; }
#memory { color: #e0af68; }
#network { color: #7aa2f7; }
#pulseaudio { color: #bb9af7; }
#pulseaudio.muted { color: #565f89; }
#battery { color: #9ece6a; }
#battery.warning { color: #e0af68; }
#battery.critical { color: #f7768e; }
#custom-power { color: #f7768e; font-size: 15px; padding: 0 13px; margin-right: 4px; }
#custom-power:hover { color: #ff9e64; }
#tray { padding: 1px 10px; }
tooltip {
  background: #1a1b26;
  border: 1px solid #7aa2f7;
  border-radius: 12px;
}
tooltip label { color: #c0caf5; }

/* Tokyo Night Aurora launcher */
window {
  margin: 0;
  background: alpha(#1a1b26, 0.78);
  border: 2px solid #7aa2f7;
  border-radius: 20px;
  font-family: "JetBrainsMono Nerd Font";
}
#input {
  margin: 14px;
  padding: 12px 16px;
  color: #c0caf5;
  background: alpha(#292e42, 0.9);
  border: none;
  border-radius: 14px;
  font-size: 15px;
}
#inner-box { margin: 6px 14px 14px 14px; }
#entry {
  padding: 8px 12px;
  margin: 2px 0;
  border-radius: 12px;
}
#entry:selected {
  background: linear-gradient(45deg, alpha(#7aa2f7, 0.9), alpha(#bb9af7, 0.9));
}
#entry:selected #text { color: #1a1b26; }
#text { color: #c0caf5; margin-left: 8px; }
#img { margin-right: 6px; }
